// A simple string hashing to assign stable visual details based on name
function getStableHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  return Math.abs(hash);
}

// Global enriched database object
const countryData = {};

// Enrich raw data on startup
Object.keys(rawCountryData).forEach(continentKey => {
  countryData[continentKey] = rawCountryData[continentKey].map(country => {
    const hash = getStableHash(country.name);
    
    // Assign SVG path
    const svgPath = country.svgPath || realCountryPaths[country.id] || mapPaths[hash % mapPaths.length];
    
    // Enrich universities
    const enrichedUniversities = country.universities.map((uni, index) => {
      const uniHash = getStableHash(uni.name);
      
      // Extract city from university name if possible, otherwise default to country name
      let city = uni.location || "";
      if (!city) {
        if (uni.name.includes("in ")) {
          city = uni.name.split("in ")[1];
        } else if (uni.name.includes("at ")) {
          city = uni.name.split("at ")[1];
        } else if (uni.name.includes("of ")) {
          city = uni.name.split("of ")[1];
        } else if (uni.name.includes(", ")) {
          city = uni.name.split(", ")[1];
        } else {
          // extract the last word or default
          const words = uni.name.split(" ");
          city = words[words.length - 1];
        }
        
        // Clean up text
        city = city.replace(/[()]/g, "").trim();
        if (city.length < 3 || city.includes("Technology") || city.includes("Science") || city.includes("Management")) {
          city = country.name;
        }
      }

      // Dynamic student counts
      const students = uni.students || `${((uniHash % 30) + 5).toFixed(0)}.000`;
      
      // Dynamic descriptions
      const description = uni.description || `${uni.name} in ${city} offers excellent study conditions for international students. It features practice-oriented study programs, a modern campus life, and strong connections with local industry and professional partners. Perfectly suited for student exchange in Visual Interface Design or related fields.`;
      
      // Select dynamic slides images (2 images per university) from local banners
      let matchedBanner = null;
      const uniNameClean = uni.name.toLowerCase().replace(/[^a-z0-9]/g, "");
      for (let i = 0; i < bannerImages.length; i++) {
        const bannerFile = bannerImages[i];
        const baseName = bannerFile.split("/").pop().split(".")[0].toLowerCase().replace(/[^a-z0-9]/g, "");
        
        // Match conditions
        if (uniNameClean.includes(baseName) || baseName.includes(uniNameClean)) {
          matchedBanner = bannerFile;
          break;
        }
        if (baseName.includes("nelsonmandela") && uniNameClean.includes("nelsonmandela")) {
          matchedBanner = bannerFile;
          break;
        }
        if (baseName.includes("cairo") && uniNameClean.includes("cairo")) {
          matchedBanner = bannerFile;
          break;
        }
        if (baseName.includes("alcala") && (uniNameClean.includes("alcal") || uniNameClean.includes("alcalá"))) {
          matchedBanner = bannerFile;
          break;
        }
        if (baseName.includes("coruna") && (uniNameClean.includes("corun") || uniNameClean.includes("coruña"))) {
          matchedBanner = bannerFile;
          break;
        }
        if (baseName.includes("southerndenmark") && uniNameClean.includes("southerndenmark")) {
          matchedBanner = bannerFile;
          break;
        }
        if (baseName.includes("jinan") && uniNameClean.includes("jinan")) {
          matchedBanner = bannerFile;
          break;
        }
      }

      let uniImages;
      if (matchedBanner) {
        // If matched, first image is the specific school banner, second is a random fallback banner
        uniImages = [
          matchedBanner,
          bannerImages[(uniHash + 1) % bannerImages.length]
        ];
      } else {
        // If not matched, select 2 random fallback banners
        uniImages = [
          bannerImages[uniHash % bannerImages.length],
          bannerImages[(uniHash + 1) % bannerImages.length]
        ];
      }

      // Student testimonial portrait photos (vertical format)
      // Uses the global testimonialImages array with 24 unique images
      let uniTestimonialPhotos = [
        testimonialImages[uniHash % testimonialImages.length],
        testimonialImages[(uniHash + 1) % testimonialImages.length]
      ];

      // Handpicked custom photos for contextually matching schools
      const lowerName = uni.name.toLowerCase();
      if (lowerName.includes("nelson mandela")) {
        uniTestimonialPhotos = [
          "https://images.unsplash.com/photo-1494790108377-be9c29b29330?auto=format&fit=crop&w=400&h=600&q=80",
          "https://images.unsplash.com/photo-1500648767791-00dcc994a43e?auto=format&fit=crop&w=400&h=600&q=80"
        ];
      } else if (lowerName.includes("stellenbosch")) {
        uniTestimonialPhotos = [
          "https://images.unsplash.com/photo-1524504388940-b1c1722653e1?auto=format&fit=crop&w=400&h=600&q=80",
          "https://images.unsplash.com/photo-1501196354995-cbb51c65aaea?auto=format&fit=crop&w=400&h=600&q=80"
        ];
      } else if (lowerName.includes("cairo")) {
        uniTestimonialPhotos = [
          "https://images.unsplash.com/photo-1544005313-94ddf0286df2?auto=format&fit=crop&w=400&h=600&q=80",
          "https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?auto=format&fit=crop&w=400&h=600&q=80"
        ];
      } else if (lowerName.includes("akhawayn")) {
        uniTestimonialPhotos = [
          "https://images.unsplash.com/photo-1534528741775-53994a69daeb?auto=format&fit=crop&w=400&h=600&q=80",
          "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?auto=format&fit=crop&w=400&h=600&q=80"
        ];
      }

      // Mock exchange course lists
      const mockCourseLists = [
        ["UX Design Foundation", "Visual Branding", "Motion Graphics", "Human-Computer Interaction", "Interactive Prototyping"],
        ["Creative Coding", "Design Systems", "Web Technologies", "Digital Storytelling", "Interface Typography"],
        ["Advanced UI Architecture", "Design Systems in Practice", "User Research Methods", "Information Design", "Service Design Studio"],
        ["Virtual Reality Design", "Audio-Visual Systems", "Graphic Design History", "Sustainable Interaction", "Cognitive Ergonomics"]
      ];
      const courses = mockCourseLists[uniHash % mockCourseLists.length];

      // Mock semester dates
      const mockDates = [
        { deadline: "May 15", start: "October 1", orientation: "September 25" },
        { deadline: "June 1", start: "September 15", orientation: "September 8" },
        { deadline: "October 15", start: "March 1", orientation: "February 22" },
        { deadline: "November 1", start: "February 15", orientation: "February 8" }
      ];
      const dates = mockDates[uniHash % mockDates.length];

      // Mock testimonials
      const mockTestimonials = [
        { quote: "Choosing this university was the best decision of my study life. The campus vibes, student clubs, and close support made integration incredibly smooth!", author: "Sarah (Visual Interface Design Student)" },
        { quote: "The professors were highly supportive, and working in the interactive design labs here helped me build my portfolio enormously.", author: "Max (User Experience Design Student)" },
        { quote: "Living in this city is an absolute dream! The local culture, campus activities, and new international friends made this semester unforgettable.", author: "Elena (Interface Design Student)" },
        { quote: "An excellent academic environment with state-of-the-art facilities. The practice-oriented courses gave me insights into actual industry workflows.", author: "Jonas (Digital Product Design Student)" }
      ];
      const testimonial = mockTestimonials[uniHash % mockTestimonials.length];
      
      return {
        name: uni.name,
        location: city,
        students: students,
        description: description,
        images: uniImages,
        testimonialPhotos: uniTestimonialPhotos,
        courses: courses,
        dates: dates,
        testimonial: testimonial
      };
    });
    
    return {
      id: country.id,
      name: country.name,
      flag: country.flag,
      description: country.description,
      popularity: (hash % 15) + 83, // 83 to 98
      places: (hash % 8) + 4,        // 4 to 12
      svgPath: svgPath,
      universities: enrichedUniversities
    };
  });
});

